import type { LedgerEntryDto } from '../../services/kt/models';

export type SoCaiPageSession = {
  accountCode: string;
  accountName: string;
  fromDate?: string;
  toDate?: string;
  items: LedgerEntryDto[];
  totalCount?: number;
  page?: number;
  pageSize?: number;
};

export type SoChiTietPageSession = {
  month: string;
  year: string;
  accountCode: string;
  accountName: string;
  items: LedgerEntryDto[];
  totalCount?: number;
  page?: number;
  pageSize?: number;
};

export type SoTongHopPageSession = {
  month: string;
  year: string;
  level: string;
  items: Array<{
    accountCode: string;
    accountName: string;
    debitAmount: number;
    creditAmount: number;
  }>;
  totalCount?: number;
  page?: number;
  pageSize?: number;
};

export type CashLedgerPageSession = {
  accountCode?: string;
  accountName?: string;
  fromDate?: string;
  toDate?: string;
  items: LedgerEntryDto[];
  totalCount?: number;
  page?: number;
  pageSize?: number;
};

const soCaiCache = new Map<string, SoCaiPageSession>();
const soChiTietCache = new Map<string, SoChiTietPageSession>();
const soTongHopCache = new Map<string, SoTongHopPageSession>();
const cashLedgerCache = new Map<string, CashLedgerPageSession>();

export function getSoCaiPageSession(pathKey: string): SoCaiPageSession | undefined {
  return soCaiCache.get(pathKey);
}

export function saveSoCaiPageSession(pathKey: string, session: SoCaiPageSession): void {
  soCaiCache.set(pathKey, session);
}

export function getSoChiTietPageSession(pathKey: string): SoChiTietPageSession | undefined {
  return soChiTietCache.get(pathKey);
}

export function saveSoChiTietPageSession(pathKey: string, session: SoChiTietPageSession): void {
  soChiTietCache.set(pathKey, session);
}

export function getSoTongHopPageSession(pathKey: string): SoTongHopPageSession | undefined {
  return soTongHopCache.get(pathKey);
}

export function saveSoTongHopPageSession(pathKey: string, session: SoTongHopPageSession): void {
  soTongHopCache.set(pathKey, session);
}

export function getCashLedgerPageSession(pathKey: string): CashLedgerPageSession | undefined {
  return cashLedgerCache.get(pathKey);
}

export function saveCashLedgerPageSession(pathKey: string, session: CashLedgerPageSession): void {
  cashLedgerCache.set(pathKey, session);
}

/** Stable cache key for report pages (pathname + search). */
export function reportPageSessionKey(pathname: string, search: string): string {
  return pathname + search;
}
